import Foundation
import FluidAudio

@available(macOS 14.0, *)
actor FluidAudioDiarizationService {
    private let manager: OfflineDiarizerManager
    private var isPrepared = false

    init(config: OfflineDiarizerConfig = OfflineDiarizerConfig()) {
        self.manager = OfflineDiarizerManager(config: config)
    }

    func buildTranscript(
        recordingURL: URL,
        transcriptionEntries: [TranscriptionEntry],
        session: RecordingSessionData
    ) async throws -> SpeakerAttributedTranscriptDocument? {
        guard !transcriptionEntries.isEmpty else { return nil }

        try await prepareIfNeeded()
        let result = try await manager.process(recordingURL)

        let diarizationSegments = result.segments.map {
            SpeakerDiarizationSegment(
                speakerLabel: $0.speakerId,
                startTimeSeconds: Double($0.startTimeSeconds),
                endTimeSeconds: Double($0.endTimeSeconds),
                qualityScore: $0.qualityScore
            )
        }

        let chunks = transcriptionEntries.map { entry in
            let relativeTimeSeconds = relativeTime(for: entry, in: session)
            let matchedSegment = bestSegment(for: relativeTimeSeconds, segments: diarizationSegments)

            return SpeakerAttributedTranscriptChunk(
                text: entry.text,
                timestamp: entry.timestamp,
                relativeTimeSeconds: relativeTimeSeconds,
                speakerLabel: matchedSegment?.speakerLabel,
                startTimeSeconds: matchedSegment?.startTimeSeconds,
                endTimeSeconds: matchedSegment?.endTimeSeconds
            )
        }

        let fullText = chunks.map(\.text).joined(separator: "\n")
        return SpeakerAttributedTranscriptDocument(
            fullText: fullText,
            chunks: chunks,
            diarizationSegments: diarizationSegments
        )
    }

    private func prepareIfNeeded() async throws {
        guard !isPrepared else { return }
        try await manager.prepareModels()
        isPrepared = true
    }

    private func relativeTime(for entry: TranscriptionEntry, in session: RecordingSessionData) -> Double {
        let sessionDuration = max(session.duration, 0.1)
        let raw = entry.timestamp.timeIntervalSince(session.startedAt)
        return min(max(raw, 0), sessionDuration)
    }

    private func bestSegment(
        for relativeTimeSeconds: Double,
        segments: [SpeakerDiarizationSegment]
    ) -> SpeakerDiarizationSegment? {
        guard !segments.isEmpty else { return nil }

        if let containing = segments.first(where: { $0.contains(timeSeconds: relativeTimeSeconds) }) {
            return containing
        }

        return segments.min {
            distance(from: relativeTimeSeconds, to: $0) < distance(from: relativeTimeSeconds, to: $1)
        }
    }

    private func distance(from time: Double, to segment: SpeakerDiarizationSegment) -> Double {
        if segment.contains(timeSeconds: time) { return 0 }
        if time < segment.startTimeSeconds { return segment.startTimeSeconds - time }
        return time - segment.endTimeSeconds
    }
}

import AVFoundation
import Foundation

// MARK: - Recording Item

struct RecordingItem: Identifiable, Equatable {
    let id: UUID
    let url: URL
    let duration: TimeInterval   // 秒
    let createdAt: Date
    let transcriptionURL: URL?   // 配对的 .txt 转录文本文件
    let transcriptJSONURL: URL?  // 配对的结构化 transcript JSON 文件

    var formattedDate: String {
        let f = DateFormatter()
        f.dateStyle = .short
        f.timeStyle = .medium
        return f.string(from: createdAt)
    }

    var formattedDuration: String {
        let total = Int(duration)
        let m = total / 60
        let s = total % 60
        return String(format: "%d:%02d", m, s)
    }

    /// 按需从配对的 .txt 文件读取转录文本
    var transcriptionText: String? {
        guard let txtURL = transcriptionURL else { return nil }
        return try? String(contentsOf: txtURL, encoding: .utf8)
    }

    var speakerAttributedTranscript: SpeakerAttributedTranscriptDocument? {
        guard let jsonURL = transcriptJSONURL else { return nil }
        return RecordingFileService.loadTranscriptDocument(from: jsonURL)
    }

    var preferredTranscriptionText: String? {
        if let structured = speakerAttributedTranscript?.formattedText, !structured.isEmpty {
            return structured
        }
        return transcriptionText
    }

    static func == (lhs: RecordingItem, rhs: RecordingItem) -> Bool {
        lhs.id == rhs.id
    }
}

// MARK: - Recording File Service

/// 负责将录音会话 PCM 样本持久化为 WAV 文件，并管理历史录音列表。
/// 使用 PCM 直写（无需 AAC 编码），AVAudioPlayer 原生支持 WAV 回放。
@MainActor
final class RecordingFileService: ObservableObject {

    // MARK: 存储目录

    /// ~/Library/Application Support/VoicePepper/Recordings/
    var storageDirectory: URL {
        let appSupport = FileManager.default.urls(
            for: .applicationSupportDirectory, in: .userDomainMask
        ).first!
        let dir = appSupport.appendingPathComponent("VoicePepper/Recordings", isDirectory: true)
        if !FileManager.default.fileExists(atPath: dir.path) {
            try? FileManager.default.createDirectory(at: dir, withIntermediateDirectories: true)
        }
        return dir
    }

    // MARK: 列表

    @Published private(set) var recordings: [RecordingItem] = []

    func loadRecordings() {
        let dir = storageDirectory
        do {
            let urls = try FileManager.default.contentsOfDirectory(
                at: dir,
                includingPropertiesForKeys: [.contentModificationDateKey],
                options: .skipsHiddenFiles
            )
            recordings = urls
                // 同时支持 wav（新格式）和旧的空 m4a 文件（排除零字节文件）
                .filter {
                    let ext = $0.pathExtension.lowercased()
                    guard ext == "wav" || ext == "m4a" else { return false }
                    let size = (try? FileManager.default.attributesOfItem(atPath: $0.path)[.size] as? Int) ?? 0
                    return size > 0
                }
                .compactMap { url -> RecordingItem? in
                    let attrs = try? url.resourceValues(forKeys: [.contentModificationDateKey])
                    let createdAt = attrs?.contentModificationDate ?? Date()
                    let duration = Self.durationOf(url: url)
                    let txtURL = Self.txtURL(for: url)
                    let jsonURL = Self.transcriptJSONURL(for: url)
                    let hasTranscription = FileManager.default.fileExists(atPath: txtURL.path)
                    let hasTranscriptJSON = FileManager.default.fileExists(atPath: jsonURL.path)
                    return RecordingItem(
                        id: UUID(),
                        url: url,
                        duration: duration,
                        createdAt: createdAt,
                        transcriptionURL: hasTranscription ? txtURL : nil,
                        transcriptJSONURL: hasTranscriptJSON ? jsonURL : nil
                    )
                }
                .sorted { $0.createdAt > $1.createdAt }
        } catch {
            NSLog("[RecordingFileService] 无法枚举录音目录: %@", error.localizedDescription)
        }
    }

    // MARK: 保存

    /// 将整个会话的完整 PCM 样本异步写为一个 WAV 文件（合并所有 VAD 段）。
